// // This module multiplies two 8-bit vectors on the falling edge of the clock and outputs the lower 8 bits of the result.
module top_module(clk, in, cv, signal_out);input wire clk;
input wire [7:0] in, cv;
output reg [7:0] signal_out;
reg [15:0] result;

always @(posedge clk)
begin
  result = in * cv;
  signal_out = result[15:8];
end

endmodule
